`,vG="/assets/bosch_01-C1pCvpEe.jpg",wG="/assets/bosch_02-DSDfC5GO.jpg",bG="/assets/bosch_03-vJarUKPz.jpg",SG="/assets/bosch_04-CPs6xx7S.jpg",jG="/assets/bosch_05-CgG1wdNd.jpg",CG="/assets/bosch_06-CophcEv5.jpg",TG="/assets/bosch_07-CcpR5-xh.jpg",AG="/assets/bosch_08-CMiZb5lk.jpg",kG=()=>s.jsxs(EG,{id:"ap",children:[s.jsx($s,{brandName:"Bosch",description:"Bosch dryers are designed with advanced European technology, including condenser and heat-pump drying systems. When something goes wrong, accurate diagnostics are essential. Airtexno Appliance Repair provides Bosch dryer repair in Thousand Oaks and nearby Ventura County communities. If your Bosch dryer stops heating, displays an error code, or takes much longer than usual to dry clothes, our technicians can inspect the system and identify the root cause of the problem.",image1:vG,image2:wG}),s.jsx(qt,{}),s.jsx(Ps,{brandName:"Bosch",models:["Bosch condenser dryers","Bosch heat pump dryers","Compact Bosch laundry systems","Stacked washer and dryer units","European-style ventless dryers"],problems:["Dryer does not start","Dryer stops during cycle","Dryer not heating","Drying takes too long","Error codes on display","Water container filling too fast","Drum not rotating","Unusual vibration or noise"],diagnostics:[{title:"Testing heating and temperature controls",text:"We verify heating elements and thermostatic controls to ensure proper heat output and safe cycling behavior."},{title:"Checking airflow and lint accumulation",text:"We inspect internal airflow channels and lint buildup that can restrict air movement and reduce drying efficiency."},{title:"Inspecting drum rollers and drive components",text:"We check drum rollers, belts, and drive parts for wear that could cause noise, vibration, or drum rotation failure."},{title:"Reviewing control board signals and error codes",text:"We read and interpret error codes and control board signals to identify system faults such as overheating, sensor failure, or drainage problems."},{title:"Evaluating condensation and moisture systems",text:"We test the condensation reservoir, drain pump, and moisture channels to ensure proper water management in ventless Bosch dryers."}],brandSpecificTitle:"Bosch heat pump & condenser dryer issues",brandSpecificText:"Unlike traditional vented dryers, Bosch dryers often rely on internal condensation systems. Moisture is collected inside a reservoir or pumped to a drain line. If airflow channels become restricted or sensors fail, the dryer may stop early or display warning messages. These systems require proper testing of sensors, pumps, and airflow paths to determine what is affecting performance."}),s.jsx(Bs,{brandName:"Bosch Dryer",photos:[{src:bG,alt:"Bosch dryer repair work"},{src:SG,alt:"Bosch dryer maintenance"},{src:jG,alt:"Bosch dryer service"},{src:CG,alt:"Bosch dryer diagnostics"},{src:TG,alt:"Bosch dryer component repair"},{src:AG,alt:"Bosch dryer technician work"}]}),s.jsx(Ns,{faqData:[{question:"Why does my Bosch dryer take longer to dry clothes?",answer:"This may be caused by restricted airflow, sensor issues, or reduced heating performance. Condenser dryers can also slow down if moisture channels are partially blocked."},{question:"Why does my Bosch dryer show an error code?",answer:"Error codes indicate that the appliance detected a system fault such as overheating, sensor failure, or drainage problems."},{question:"Do Bosch dryers need ventilation?",answer:"Most Bosch dryers are ventless, meaning they use condensation or heat pump technology instead of external ventilation ducts."},{question:"Is it worth repairing a Bosch dryer?",answer:"Bosch appliances are generally built with high-quality components, and many issues can be repaired when diagnosed correctly."}]}),s.jsx(It,{}),s.jsx(Nt,{}),s.jsx(_t,{})]}),EG=b.div`
